200→  private setupRoutes(): void {
201→    this.bot.on("message:text", async (ctx) => {
202→      const threadId = ctx.message.message_thread_id;
203→
204→      // General topic or no thread → redirect to assistant
205→      if (!threadId) {
206→        const html = redirectToAssistant(
207→          this.telegramConfig.chatId,
208→          this.assistantTopicId,
209→        );
210→        await ctx.reply(html, { parse_mode: "HTML" });
211→        return;
212→      }
213→
214→      // Notification topic → ignore
215→      if (threadId === this.notificationTopicId) return;
216→
217→      // Assistant topic → send typing indicator and forward to assistant session
218→      if (threadId === this.assistantTopicId) {
219→        ctx.replyWithChatAction("typing").catch(() => {});
220→        handleAssistantMessage(this.assistantSession, ctx.message.text).catch(
221→          (err) => log.error({ err }, "Assistant error"),
222→        );
223→        return;
224→      }
225→
226→      // Session topic → send typing indicator and forward to core
227→      ctx.replyWithChatAction("typing").catch(() => {});
228→      (this.core as OpenACPCore)
229→        .handleMessage({
230→          channelId: "telegram",
231→          threadId: String(threadId),
232→          userId: String(ctx.from.id),
233→          text: ctx.message.text,
234→        })
235→        .catch((err) => log.error({ err }, "handleMessage error"));
236→    });
237→  }
