241→  async sendMessage(
242→    sessionId: string,
243→    content: OutgoingMessage,
244→  ): Promise<void> {
245→    // log.debug({ sessionId, type: content.type }, "Sending message to Telegram");
246→    const session = (this.core as OpenACPCore).sessionManager.getSession(
247→      sessionId,
248→    );
249→    if (!session) return;
250→    const threadId = Number(session.threadId);
251→
252→    switch (content.type) {
253→      case "thought": {
254→        // Skip thought/thinking content — it's internal agent reasoning
255→        // Users don't need to see it
256→        break;
257→      }
258→
259→      case "text": {
260→        let draft = this.sessionDrafts.get(sessionId);
261→        if (!draft) {
262→          draft = new MessageDraft(
263→            this.bot,
264→            this.telegramConfig.chatId,
265→            threadId,
266→          );
267→          this.sessionDrafts.set(sessionId, draft);
268→        }
269→        draft.append(content.text);
270→        break;
271→      }
272→
273→      case "tool_call": {
274→        await this.finalizeDraft(sessionId);
275→        const meta = content.metadata as never as {
276→          id: string;
277→          name: string;
278→          kind?: string;
279→          status?: string;
280→          content?: unknown;
281→        };
282→        const msg = await this.bot.api.sendMessage(
283→          this.telegramConfig.chatId,
284→          formatToolCall(meta),
285→          {
286→            message_thread_id: threadId,
287→            parse_mode: "HTML",
288→            disable_notification: true,
289→          },
290→        );
291→        if (!this.toolCallMessages.has(sessionId)) {
292→          this.toolCallMessages.set(sessionId, new Map());
293→        }
294→        this.toolCallMessages.get(sessionId)!.set(meta.id, {
295→          msgId: msg.message_id,
296→          name: meta.name,
297→          kind: meta.kind,
298→        });
299→        break;
300→      }
301→
302→      case "tool_update": {
303→        const meta = content.metadata as never as {
304→          id: string;
305→          name: string;
306→          kind?: string;
307→          status: string;
308→          content?: unknown;
309→        };
310→        const toolState = this.toolCallMessages.get(sessionId)?.get(meta.id);
311→        if (toolState) {
312→          // Merge name/kind from original tool_call
313→          const merged = {
314→            ...meta,
315→            name: meta.name || toolState.name,
316→            kind: meta.kind || toolState.kind,
317→          };
318→          try {
319→            await this.bot.api.editMessageText(
320→              this.telegramConfig.chatId,
321→              toolState.msgId,
322→              formatToolUpdate(merged),
323→              { parse_mode: "HTML" },
324→            );
325→          } catch {
326→            /* edit failed */
327→          }
328→        }
329→        break;
330→      }
331→
332→      case "plan": {
333→        await this.finalizeDraft(sessionId);
334→        await this.bot.api.sendMessage(
335→          this.telegramConfig.chatId,
336→          formatPlan(
337→            content.metadata as never as {
338→              entries: Array<{ content: string; status: string }>;
339→            },
340→          ),
341→          {
342→            message_thread_id: threadId,
343→            parse_mode: "HTML",
344→            disable_notification: true,
345→          },
346→        );
347→        break;
348→      }
349→
350→      case "usage": {
351→        // Show usage stats
352→        await this.bot.api.sendMessage(
353→          this.telegramConfig.chatId,
354→          formatUsage(
355→            content.metadata as never as {
356→              tokensUsed?: number;
357→              contextSize?: number;
358→              cost?: { amount: number; currency: string };
359→            },
360→          ),
361→          {
362→            message_thread_id: threadId,
363→            parse_mode: "HTML",
364→            disable_notification: true,
365→          },
366→        );
367→        break;
368→      }
369→
370→      case "session_end": {
371→        await this.finalizeDraft(sessionId);
372→        this.sessionDrafts.delete(sessionId);
373→        this.toolCallMessages.delete(sessionId);
374→        await this.cleanupSkillCommands(sessionId);
375→        await this.bot.api.sendMessage(
376→          this.telegramConfig.chatId,
377→          `✅ <b>Done</b>`,
378→          {
379→            message_thread_id: threadId,
380→            parse_mode: "HTML",
381→            disable_notification: true,
382→          },
383→        );
384→        break;
385→      }
386→
387→      case "error": {
388→        await this.finalizeDraft(sessionId);
389→        await this.bot.api.sendMessage(
390→          this.telegramConfig.chatId,
391→          `❌ <b>Error:</b> ${escapeHtml(content.text)}`,
392→          {
393→            message_thread_id: threadId,
394→            parse_mode: "HTML",
395→            disable_notification: true,
396→          },
397→        );
398→        break;
399→      }
400→    }
401→  }
