 11→export function setupCommands(
 12→  bot: Bot,
 13→  core: OpenACPCore,
 14→  chatId: number,
 15→): void {
 16→  bot.command("new", (ctx) => handleNew(ctx, core, chatId));
 17→  bot.command("new_chat", (ctx) => handleNewChat(ctx, core, chatId));
 18→  bot.command("cancel", (ctx) => handleCancel(ctx, core));
 19→  bot.command("status", (ctx) => handleStatus(ctx, core));
 20→  bot.command("agents", (ctx) => handleAgents(ctx, core));
 21→  bot.command("help", (ctx) => handleHelp(ctx));
 22→  bot.command("menu", (ctx) => handleMenu(ctx));
