 25→export function buildMenuKeyboard(): InlineKeyboard {
 26→  return new InlineKeyboard()
 27→    .text("🆕 New Session", "m:new")
 28→    .text("💬 New Chat", "m:new_chat")
 29→    .row()
 30→    .text("⛔ Cancel", "m:cancel")
 31→    .text("📊 Status", "m:status")
