 37→export function setupMenuCallbacks(
 38→  bot: Bot,
 39→  core: OpenACPCore,
 40→  chatId: number,
 41→): void {
 42→  bot.callbackQuery(/^m:/, async (ctx) => {
 43→    const data = ctx.callbackQuery.data;
 44→    try {
 45→      await ctx.answerCallbackQuery();
 46→    } catch {
 47→      /* expired or network — ignore */
 48→    }
 49→
 50→    switch (data) {
 51→      case "m:new":
 52→        await handleNew(ctx, core, chatId);
 53→        break;
 54→      case "m:new_chat":
 55→        await handleNewChat(ctx, core, chatId);
 56→        break;
 57→      case "m:cancel":
 58→        await handleCancel(ctx, core);
 59→        break;
 60→      case "m:status":
 61→        await handleStatus(ctx, core);
 62→        break;
 63→      case "m:agents":
 64→        await handleAgents(ctx, core);
 65→        break;
 66→      case "m:help":
 67→        await handleHelp(ctx);
 68→        break;
 69→    }
 70→  });
