 80→async function handleNew(
 81→  ctx: Context,
 82→  core: OpenACPCore,
 83→  chatId: number,
 84→): Promise<void> {
 85→  const rawMatch = (ctx as Context & { match: unknown }).match;
 86→  const matchStr = typeof rawMatch === "string" ? rawMatch : "";
 87→  const args = matchStr.split(" ").filter(Boolean);
 88→  const agentName = args[0];
 89→  const workspace = args[1];
 90→
 91→  log.info({ userId: ctx.from?.id, agentName }, 'New session command')
 92→
 93→  // Create topic first so threadId is ready before session events fire
 94→  let threadId: number | undefined;
 95→  try {
 96→    const topicName = `🔄 New Session`;
 97→    threadId = await createSessionTopic(botFromCtx(ctx), chatId, topicName);
 98→
 99→    // Let user know we're setting up (spawn + warm-up can take a while)
100→    await ctx.api.sendMessage(chatId, `⏳ Setting up session, please wait...`, {
101→      message_thread_id: threadId,
102→      parse_mode: "HTML",
103→    });
104→
105→    const session = await core.handleNewSession(
106→      "telegram",
107→      agentName,
108→      workspace,
109→    );
110→    session.threadId = String(threadId);
111→
112→    // Rename topic with actual agent name
113→    const finalName = `🔄 ${session.agentName} — New Session`;
114→    try {
115→      await ctx.api.editForumTopic(chatId, threadId, { name: finalName });
116→    } catch {
117→      /* ignore rename failures */
118→    }
119→
120→    await ctx.api.sendMessage(
121→      chatId,
122→      `✅ Session started\n` +
123→        `<b>Agent:</b> ${escapeHtml(session.agentName)}\n` +
124→        `<b>Workspace:</b> <code>${escapeHtml(session.workingDirectory)}</code>`,
125→      {
126→        message_thread_id: threadId,
127→        parse_mode: "HTML",
128→      },
129→    );
130→
131→    // Warm up model cache in background while user types
132→    session.warmup().catch((err) => log.error({ err }, "Warm-up error"));
133→  } catch (err) {
134→    // Clean up orphaned topic if session creation failed
135→    if (threadId) {
136→      try {
137→        await ctx.api.deleteForumTopic(chatId, threadId);
138→      } catch {
139→        /* ignore cleanup failures */
140→      }
141→    }
142→    const message = err instanceof Error ? err.message : String(err);
143→    await ctx.reply(`❌ ${escapeHtml(message)}`, { parse_mode: "HTML" });
144→  }
145→}
