203→async function handleCancel(ctx: Context, core: OpenACPCore): Promise<void> {
204→  const threadId = ctx.message?.message_thread_id;
205→  if (!threadId) return;
206→
207→  const session = core.sessionManager.getSessionByThread(
208→    "telegram",
209→    String(threadId),
210→  );
211→  if (session) {
212→    log.info({ sessionId: session.id }, 'Cancel session command')
213→    await session.cancel();
214→    await ctx.reply("⛔ Session cancelled.", { parse_mode: "HTML" });
215→  }
216→}
