233→      );
234→    } else {
235→      await ctx.reply("No active session in this topic.", {
236→        parse_mode: "HTML",
237→      });
238→    }
239→  } else {
240→    const sessions = core.sessionManager.listSessions("telegram");
241→    const active = sessions.filter(
242→      (s) => s.status === "active" || s.status === "initializing",
243→    );
244→    await ctx.reply(
245→      `<b>OpenACP Status</b>\n` +
246→        `Active sessions: ${active.length}\n` +
247→        `Total sessions: ${sessions.length}`,
248→      { parse_mode: "HTML" },
249→    );
250→  }
251→}
