253→async function handleAgents(ctx: Context, core: OpenACPCore): Promise<void> {
254→  const agents = core.agentManager.getAvailableAgents();
255→  const defaultAgent = core.configManager.get().defaultAgent;
256→  const lines = agents.map(
257→    (a) =>
258→      `• <b>${escapeHtml(a.name)}</b>${a.name === defaultAgent ? " (default)" : ""}\n` +
259→      `  <code>${escapeHtml(a.command)} ${a.args.map((arg) => escapeHtml(arg)).join(" ")}</code>`,
260→  );
261→  const text =
262→    lines.length > 0
