 14→/** Resolve an agent command to a directly executable form (avoids shell wrappers) */
 15→function resolveAgentCommand(cmd: string): { command: string; args: string[] } {
 16→  // 1. Check local node_modules for the package's actual JS entry point
 17→  const packageDirs = [
 18→    path.resolve(process.cwd(), 'node_modules', '@zed-industries', cmd, 'dist', 'index.js'),
 19→    path.resolve(process.cwd(), 'node_modules', cmd, 'dist', 'index.js'),
 20→  ]
 21→  for (const jsPath of packageDirs) {
 22→    if (fs.existsSync(jsPath)) {
 23→      return { command: process.execPath, args: [jsPath] }
 24→    }
 25→  }
 26→
 27→  // 2. Check local .bin — if it's a JS file with shebang, run with node directly
 28→  const localBin = path.resolve(process.cwd(), 'node_modules', '.bin', cmd)
 29→  if (fs.existsSync(localBin)) {
 30→    const content = fs.readFileSync(localBin, 'utf-8')
 31→    if (content.startsWith('#!/usr/bin/env node')) {
 32→      return { command: process.execPath, args: [localBin] }
 33→    }
 34→    // Shell wrapper — try to find the target JS file
 35→    const match = content.match(/"([^"]+\.js)"/)
 36→    if (match) {
 37→      const target = path.resolve(path.dirname(localBin), match[1])
 38→      if (fs.existsSync(target)) {
 39→        return { command: process.execPath, args: [target] }
 40→      }
 41→    }
 42→  }
 43→
 44→  // 3. Try resolving from PATH using which
 45→  try {
 46→    const fullPath = execSync(`which ${cmd}`, { encoding: 'utf-8' }).trim()
 47→    if (fullPath) {
 48→      const content = fs.readFileSync(fullPath, 'utf-8')
 49→      if (content.startsWith('#!/usr/bin/env node')) {
 50→        return { command: process.execPath, args: [fullPath] }
 51→      }
 52→    }
 53→  } catch {
 54→    // which failed
 55→  }
 56→
 57→  // 4. Fallback: use command as-is
 58→  return { command: cmd, args: [] }
 59→}
