283→        })
284→
285→        const state: TerminalState = {
286→          process: childProcess,
287→          output: '',
288→          exitStatus: null,
289→        }
290→        self.terminals.set(terminalId, state)
291→
292→        const outputByteLimit = params.outputByteLimit ?? MAX_OUTPUT_BYTES
293→
294→        const appendOutput = (chunk: string) => {
295→          state.output += chunk
296→          // Truncate from the beginning if over limit
297→          const bytes = Buffer.byteLength(state.output, 'utf-8')
298→          if (bytes > outputByteLimit) {
299→            // Find truncation point at character boundary
300→            const excess = bytes - outputByteLimit
301→            state.output = state.output.slice(excess)
302→          }
303→        }
304→
305→        childProcess.stdout?.on('data', (chunk: Buffer) => appendOutput(chunk.toString()))
306→        childProcess.stderr?.on('data', (chunk: Buffer) => appendOutput(chunk.toString()))
307→
308→        childProcess.on('exit', (code, signal) => {
309→          state.exitStatus = { exitCode: code, signal }
310→        })
311→
312→        return { terminalId }
313→      },
314→
315→      async terminalOutput(params) {
316→        const state = self.terminals.get(params.terminalId)
317→        if (!state) {
318→          throw new Error(`Terminal not found: ${params.terminalId}`)
319→        }
320→        return {
321→          output: state.output,
322→          truncated: false,
323→          exitStatus: state.exitStatus
324→            ? { exitCode: state.exitStatus.exitCode, signal: state.exitStatus.signal }
325→            : undefined,
326→        }
327→      },
328→
329→      async waitForTerminalExit(params) {
330→        const state = self.terminals.get(params.terminalId)
331→        if (!state) {
332→          throw new Error(`Terminal not found: ${params.terminalId}`)
333→        }
334→        if (state.exitStatus !== null) {
335→          return { exitCode: state.exitStatus.exitCode, signal: state.exitStatus.signal }
336→        }
337→        return new Promise((resolve) => {
338→          state.process.on('exit', (code, signal) => {
339→            resolve({ exitCode: code, signal })
340→          })
341→        })
342→      },
343→
344→      async killTerminal(params) {
345→        const state = self.terminals.get(params.terminalId)
346→        if (!state) {
347→          throw new Error(`Terminal not found: ${params.terminalId}`)
348→        }
349→        state.process.kill('SIGTERM')
350→        return {}
351→      },
352→
353→      async releaseTerminal(params) {
354→        const state = self.terminals.get(params.terminalId)
355→        if (!state) {
356→          return
357→        }
358→        state.process.kill('SIGKILL')
359→        self.terminals.delete(params.terminalId)
360→      },
361→    }
362→  }
363→
364→  async prompt(text: string): Promise<PromptResponse> {
365→    return this.connection.prompt({
366→      sessionId: this.sessionId,
367→      prompt: [{ type: 'text', text }],
368→    })
369→  }
370→
371→  async cancel(): Promise<void> {
372→    await this.connection.cancel({ sessionId: this.sessionId })
373→  }
374→
375→  async destroy(): Promise<void> {
376→    // Cleanup terminals
377→    for (const [, t] of this.terminals) {
378→      t.process.kill('SIGKILL')
379→    }
380→    this.terminals.clear()
381→
382→    // Kill agent subprocess
383→    this.child.kill('SIGTERM')
384→    setTimeout(() => {
385→      if (!this.child.killed) this.child.kill('SIGKILL')
386→    }, 10_000)
387→  }
388→}
