  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'openacp-resume-'))
    filePath = path.join(tmpDir, 'sessions.json')
    store = new JsonFileSessionStore(filePath, 30)
