162→  private applyEnvOverrides(raw: Record<string, unknown>): void {
163→    const overrides: [string, string[]][] = [
164→      ['OPENACP_TELEGRAM_BOT_TOKEN', ['channels', 'telegram', 'botToken']],
165→      ['OPENACP_TELEGRAM_CHAT_ID', ['channels', 'telegram', 'chatId']],
166→      ['OPENACP_DEFAULT_AGENT', ['defaultAgent']],
167→    ]
168→    for (const [envVar, configPath] of overrides) {
169→      const value = process.env[envVar]
170→      if (value !== undefined) {
171→        let target = raw as Record<string, any>
172→        for (let i = 0; i < configPath.length - 1; i++) {
173→          if (!target[configPath[i]]) target[configPath[i]] = {}
174→          target = target[configPath[i]]
175→        }
176→        const key = configPath[configPath.length - 1]
177→        // Convert chatId to number
178→        target[key] = key === 'chatId' ? Number(value) : value
179→      }
180→    }
181→
182→    // Logging env var overrides
183→    if (process.env.OPENACP_LOG_LEVEL) {
184→      raw.logging = raw.logging || {}
185→      ;(raw.logging as Record<string, unknown>).level = process.env.OPENACP_LOG_LEVEL
186→    }
187→    if (process.env.OPENACP_LOG_DIR) {
188→      raw.logging = raw.logging || {}
