197→  private deepMerge(target: Record<string, any>, source: Record<string, any>): void {
198→    for (const key of Object.keys(source)) {
199→      if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
200→        if (!target[key]) target[key] = {}
201→        this.deepMerge(target[key], source[key])
202→      } else {
203→        target[key] = source[key]
204→      }
205→    }
206→  }
