  1→import { spawn, execSync, type ChildProcess } from 'node:child_process'
  2→import { Transform } from 'node:stream'
  3→import fs from 'node:fs'
  4→import path from 'node:path'
  5→import { randomUUID } from 'node:crypto'
  6→import { ClientSideConnection, ndJsonStream } from '@agentclientprotocol/sdk'
  7→import type { Agent, Client, PromptResponse, PermissionOption as SdkPermissionOption } from '@agentclientprotocol/sdk'
  8→import { nodeToWebWritable, nodeToWebReadable } from './streams.js'
  9→import { StderrCapture } from './stderr-capture.js'
 10→import type { AgentDefinition, AgentEvent, PermissionRequest } from './types.js'
 11→import { createChildLogger } from './log.js'
 12→const log = createChildLogger({ module: 'agent-instance' })
 13→
 14→/** Resolve an agent command to a directly executable form (avoids shell wrappers) */
 15→function resolveAgentCommand(cmd: string): { command: string; args: string[] } {
 16→  // 1. Check local node_modules for the package's actual JS entry point
 17→  const packageDirs = [
 18→    path.resolve(process.cwd(), 'node_modules', '@zed-industries', cmd, 'dist', 'index.js'),
 19→    path.resolve(process.cwd(), 'node_modules', cmd, 'dist', 'index.js'),
 20→  ]
 21→  for (const jsPath of packageDirs) {
 22→    if (fs.existsSync(jsPath)) {
 23→      return { command: process.execPath, args: [jsPath] }
 24→    }
 25→  }
 26→
 27→  // 2. Check local .bin — if it's a JS file with shebang, run with node directly
 28→  const localBin = path.resolve(process.cwd(), 'node_modules', '.bin', cmd)
 29→  if (fs.existsSync(localBin)) {
 30→    const content = fs.readFileSync(localBin, 'utf-8')
 31→    if (content.startsWith('#!/usr/bin/env node')) {
 32→      return { command: process.execPath, args: [localBin] }
 33→    }
 34→    // Shell wrapper — try to find the target JS file
 35→    const match = content.match(/"([^"]+\.js)"/)
 36→    if (match) {
 37→      const target = path.resolve(path.dirname(localBin), match[1])
 38→      if (fs.existsSync(target)) {
 39→        return { command: process.execPath, args: [target] }
 40→      }
 41→    }
 42→  }
 43→
 44→  // 3. Try resolving from PATH using which
 45→  try {
 46→    const fullPath = execSync(`which ${cmd}`, { encoding: 'utf-8' }).trim()
 47→    if (fullPath) {
 48→      const content = fs.readFileSync(fullPath, 'utf-8')
 49→      if (content.startsWith('#!/usr/bin/env node')) {
 50→        return { command: process.execPath, args: [fullPath] }
 51→      }
 52→    }
 53→  } catch {
 54→    // which failed
 55→  }
 56→
 57→  // 4. Fallback: use command as-is
 58→  return { command: cmd, args: [] }
 59→}
 60→
 61→interface TerminalState {
 62→  process: ChildProcess
 63→  output: string
 64→  exitStatus: { exitCode: number | null; signal: string | null } | null
 65→}
 66→
 67→export class AgentInstance {
 68→  private connection!: ClientSideConnection
 69→  private child!: ChildProcess
 70→  private stderrCapture!: StderrCapture
 71→  private terminals: Map<string, TerminalState> = new Map()
 72→
 73→  sessionId!: string
 74→  agentName: string
 75→
 76→  // Callbacks — set by core when wiring events
 77→  onSessionUpdate: (event: AgentEvent) => void = () => {}
 78→  onPermissionRequest: (request: PermissionRequest) => Promise<string> = async () => ''
 79→
 80→  private constructor(agentName: string) {
 81→    this.agentName = agentName
 82→  }
 83→
 84→  static async spawn(agentDef: AgentDefinition, workingDirectory: string): Promise<AgentInstance> {
 85→    const instance = new AgentInstance(agentDef.name)
 86→
 87→    // 1. Resolve command: find the actual JS entry point to avoid shell wrappers
 88→    const resolved = resolveAgentCommand(agentDef.command)
 89→    log.debug({ agentName: agentDef.name, command: resolved.command, args: resolved.args }, 'Spawning agent')
 90→    const spawnStart = Date.now()
 91→
 92→    // Spawn subprocess
 93→    instance.child = spawn(resolved.command, [...resolved.args, ...agentDef.args], {
 94→      stdio: ['pipe', 'pipe', 'pipe'],
 95→      cwd: workingDirectory,
 96→      env: { ...process.env, ...agentDef.env },
 97→    })
 98→
 99→    // 2. Handle spawn errors (e.g., command not found)
100→    await new Promise<void>((resolve, reject) => {
101→      instance.child.on('error', (err) => {
102→        reject(new Error(`Failed to spawn agent "${agentDef.name}": ${err.message}. Is "${agentDef.command}" installed?`))
103→      })
104→      instance.child.on('spawn', () => resolve())
105→    })
106→
107→    // 3. Capture stderr
108→    instance.stderrCapture = new StderrCapture(50)
109→    instance.child.stderr!.on('data', (chunk: Buffer) => {
110→      instance.stderrCapture.append(chunk.toString())
111→    })
112→
113→    // 3. Create ACP stream with raw NDJSON logging
114→    const stdinLogger = new Transform({
115→      transform(chunk, _enc, cb) {
116→        log.debug({ direction: 'send', raw: chunk.toString().trimEnd() }, 'ACP raw')
117→        cb(null, chunk)
118→      },
119→    })
120→    stdinLogger.pipe(instance.child.stdin!)
121→
122→    const stdoutLogger = new Transform({
123→      transform(chunk, _enc, cb) {
124→        log.debug({ direction: 'recv', raw: chunk.toString().trimEnd() }, 'ACP raw')
125→        cb(null, chunk)
126→      },
127→    })
128→    instance.child.stdout!.pipe(stdoutLogger)
129→
130→    const toAgent = nodeToWebWritable(stdinLogger)
131→    const fromAgent = nodeToWebReadable(stdoutLogger)
132→    const stream = ndJsonStream(toAgent, fromAgent)
133→
134→    // 4. Create ClientSideConnection
135→    instance.connection = new ClientSideConnection(
136→      (_agent: Agent): Client => instance.createClient(_agent),
137→      stream,
138→    )
139→
140→    // 5. ACP handshake
141→    await instance.connection.initialize({
142→      protocolVersion: 1,
143→      clientCapabilities: {
144→        fs: { readTextFile: true, writeTextFile: true },
145→        terminal: true,
146→      },
147→    })
148→
149→    // 6. Create session
150→    const response = await instance.connection.newSession({
151→      cwd: workingDirectory,
152→      mcpServers: [],
153→    })
154→    instance.sessionId = response.sessionId
155→
156→    // 7. Crash detection
157→    instance.child.on('exit', (code, signal) => {
158→      log.info({ sessionId: instance.sessionId, exitCode: code, signal }, 'Agent process exited')
159→      if (code !== 0 && code !== null) {
160→        const stderr = instance.stderrCapture.getLastLines()
161→        instance.onSessionUpdate({
162→          type: 'error',
163→          message: `Agent crashed (exit code ${code})\n${stderr}`,
164→        })
165→      }
166→    })
167→
168→    instance.connection.closed.then(() => {
169→      log.debug({ sessionId: instance.sessionId }, 'ACP connection closed')
170→    })
171→
172→    log.info({ sessionId: response.sessionId, durationMs: Date.now() - spawnStart }, 'Agent spawn complete')
173→    return instance
174→  }
175→
176→  // createClient — implemented in Task 6b
177→  private createClient(_agent: Agent): Client {
178→    const self = this
179→    const MAX_OUTPUT_BYTES = 1024 * 1024 // 1MB cap
180→
181→    return {
182→      // ── Session updates ──────────────────────────────────────────────────
183→      async sessionUpdate(params) {
184→        const update = params.update
185→        let event: AgentEvent | null = null
186→
187→        switch (update.sessionUpdate) {
188→          case 'agent_message_chunk':
189→            if (update.content.type === 'text') {
190→              event = { type: 'text', content: update.content.text }
191→            }
192→            break
193→          case 'agent_thought_chunk':
194→            if (update.content.type === 'text') {
195→              event = { type: 'thought', content: update.content.text }
196→            }
197→            break
198→          case 'tool_call':
199→            event = {
200→              type: 'tool_call',
201→              id: update.toolCallId,
202→              name: update.title,
203→              kind: update.kind ?? undefined,
204→              status: update.status ?? 'pending',
205→              content: update.content ?? undefined,
206→            }
207→            break
208→          case 'tool_call_update':
209→            event = {
210→              type: 'tool_update',
211→              id: update.toolCallId,
212→              status: update.status ?? 'pending',
213→              content: update.content ?? undefined,
214→            }
215→            break
216→          case 'plan':
217→            event = { type: 'plan', entries: update.entries }
218→            break
219→          case 'usage_update':
220→            event = {
221→              type: 'usage',
222→              tokensUsed: update.used,
223→              contextSize: update.size,
224→              cost: update.cost ?? undefined,
225→            }
226→            break
227→          case 'available_commands_update':
228→            event = { type: 'commands_update', commands: update.availableCommands }
229→            break
230→          default:
231→            // Unknown update type — ignore
232→            return
233→        }
234→
235→        if (event !== null) {
236→          self.onSessionUpdate(event)
237→        }
238→      },
239→
240→      // ── Permission requests ──────────────────────────────────────────────
241→      async requestPermission(params) {
242→        const permissionRequest: PermissionRequest = {
243→          id: params.toolCall.toolCallId,
244→          description: params.toolCall.title ?? params.toolCall.toolCallId,
245→          options: params.options.map((opt: SdkPermissionOption) => ({
246→            id: opt.optionId,
247→            label: opt.name,
248→            isAllow: opt.kind === 'allow_once' || opt.kind === 'allow_always',
249→          })),
250→        }
251→
252→        const selectedOptionId = await self.onPermissionRequest(permissionRequest)
253→        return {
254→          outcome: { outcome: 'selected' as const, optionId: selectedOptionId },
255→        }
256→      },
257→
258→      // ── File operations ──────────────────────────────────────────────────
259→      async readTextFile(params) {
260→        const content = await fs.promises.readFile(params.path, 'utf-8')
261→        return { content }
262→      },
263→
264→      async writeTextFile(params) {
265→        await fs.promises.mkdir(path.dirname(params.path), { recursive: true })
266→        await fs.promises.writeFile(params.path, params.content, 'utf-8')
267→        return {}
268→      },
269→
270→      // ── Terminal operations ──────────────────────────────────────────────
271→      async createTerminal(params) {
272→        const terminalId = randomUUID()
273→        const args = params.args ?? []
274→        const env: Record<string, string> = {}
275→        for (const ev of params.env ?? []) {
276→          env[ev.name] = ev.value
277→        }
278→
279→        const childProcess = spawn(params.command, args, {
280→          cwd: params.cwd ?? undefined,
281→          env: { ...process.env, ...env },
282→          shell: false,
283→        })
284→
285→        const state: TerminalState = {
286→          process: childProcess,
287→          output: '',
288→          exitStatus: null,
289→        }
290→        self.terminals.set(terminalId, state)
291→
292→        const outputByteLimit = params.outputByteLimit ?? MAX_OUTPUT_BYTES
293→
294→        const appendOutput = (chunk: string) => {
295→          state.output += chunk
296→          // Truncate from the beginning if over limit
297→          const bytes = Buffer.byteLength(state.output, 'utf-8')
298→          if (bytes > outputByteLimit) {
299→            // Find truncation point at character boundary
300→            const excess = bytes - outputByteLimit
301→            state.output = state.output.slice(excess)
302→          }
303→        }
304→
305→        childProcess.stdout?.on('data', (chunk: Buffer) => appendOutput(chunk.toString()))
306→        childProcess.stderr?.on('data', (chunk: Buffer) => appendOutput(chunk.toString()))
307→
308→        childProcess.on('exit', (code, signal) => {
309→          state.exitStatus = { exitCode: code, signal }
310→        })
311→
312→        return { terminalId }
313→      },
314→
315→      async terminalOutput(params) {
316→        const state = self.terminals.get(params.terminalId)
317→        if (!state) {
318→          throw new Error(`Terminal not found: ${params.terminalId}`)
319→        }
320→        return {
321→          output: state.output,
322→          truncated: false,
323→          exitStatus: state.exitStatus
324→            ? { exitCode: state.exitStatus.exitCode, signal: state.exitStatus.signal }
325→            : undefined,
326→        }
327→      },
328→
329→      async waitForTerminalExit(params) {
330→        const state = self.terminals.get(params.terminalId)
331→        if (!state) {
332→          throw new Error(`Terminal not found: ${params.terminalId}`)
333→        }
334→        if (state.exitStatus !== null) {
335→          return { exitCode: state.exitStatus.exitCode, signal: state.exitStatus.signal }
336→        }
337→        return new Promise((resolve) => {
338→          state.process.on('exit', (code, signal) => {
339→            resolve({ exitCode: code, signal })
340→          })
341→        })
342→      },
343→
344→      async killTerminal(params) {
345→        const state = self.terminals.get(params.terminalId)
346→        if (!state) {
347→          throw new Error(`Terminal not found: ${params.terminalId}`)
348→        }
349→        state.process.kill('SIGTERM')
350→        return {}
351→      },
352→
353→      async releaseTerminal(params) {
354→        const state = self.terminals.get(params.terminalId)
355→        if (!state) {
356→          return
357→        }
358→        state.process.kill('SIGKILL')
359→        self.terminals.delete(params.terminalId)
360→      },
361→    }
362→  }
363→
364→  async prompt(text: string): Promise<PromptResponse> {
365→    return this.connection.prompt({
366→      sessionId: this.sessionId,
367→      prompt: [{ type: 'text', text }],
368→    })
369→  }
370→
371→  async cancel(): Promise<void> {
372→    await this.connection.cancel({ sessionId: this.sessionId })
373→  }
374→
375→  async destroy(): Promise<void> {
376→    // Cleanup terminals
377→    for (const [, t] of this.terminals) {
378→      t.process.kill('SIGKILL')
379→    }
380→    this.terminals.clear()
381→
382→    // Kill agent subprocess
383→    this.child.kill('SIGTERM')
384→    setTimeout(() => {
385→      if (!this.child.killed) this.child.kill('SIGKILL')
386→    }, 10_000)
387→  }
388→}
