147→async function handleNewChat(
148→  ctx: Context,
149→  core: OpenACPCore,
150→  chatId: number,
151→): Promise<void> {
152→  const threadId = ctx.message?.message_thread_id;
153→  if (!threadId) {
154→    await ctx.reply(
155→      "Use /new_chat inside a session topic to inherit its config.",
156→      { parse_mode: "HTML" },
157→    );
158→    return;
159→  }
160→
161→  try {
162→    const session = await core.handleNewChat("telegram", String(threadId));
163→    if (!session) {
164→      await ctx.reply("No active session in this topic.", {
165→        parse_mode: "HTML",
166→      });
167→      return;
168→    }
169→
170→    const topicName = `🔄 ${session.agentName} — New Chat`;
171→    const newThreadId = await createSessionTopic(
172→      botFromCtx(ctx),
173→      chatId,
174→      topicName,
175→    );
176→
177→    await ctx.api.sendMessage(chatId, `⏳ Setting up session, please wait...`, {
178→      message_thread_id: newThreadId,
179→      parse_mode: "HTML",
180→    });
181→
182→    session.threadId = String(newThreadId);
183→
184→    await ctx.api.sendMessage(
185→      chatId,
186→      `✅ New chat (same agent &amp; workspace)\n` +
187→        `<b>Agent:</b> ${escapeHtml(session.agentName)}\n` +
188→        `<b>Workspace:</b> <code>${escapeHtml(session.workingDirectory)}</code>`,
189→      {
190→        message_thread_id: newThreadId,
191→        parse_mode: "HTML",
192→      },
193→    );
194→
195→    // Warm up model cache in background while user types
196→    session.warmup().catch((err) => log.error({ err }, "Warm-up error"));
197→  } catch (err) {
198→    const message = err instanceof Error ? err.message : String(err);
199→    await ctx.reply(`❌ ${escapeHtml(message)}`, { parse_mode: "HTML" });
200→  }
201→}
