218→async function handleStatus(ctx: Context, core: OpenACPCore): Promise<void> {
219→  const threadId = ctx.message?.message_thread_id;
220→  if (threadId) {
221→    const session = core.sessionManager.getSessionByThread(
222→      "telegram",
223→      String(threadId),
224→    );
225→    if (session) {
226→      await ctx.reply(
227→        `<b>Session:</b> ${escapeHtml(session.name || session.id)}\n` +
228→          `<b>Agent:</b> ${escapeHtml(session.agentName)}\n` +
229→          `<b>Status:</b> ${escapeHtml(session.status)}\n` +
230→          `<b>Workspace:</b> <code>${escapeHtml(session.workingDirectory)}</code>\n` +
231→          `<b>Queue:</b> ${session.promptQueue.length} pending`,
