283→// grammy's Context exposes .api (the bot's Api instance) and internally the bot
284→// We need access to the bot instance for createSessionTopic (which uses bot.api.createForumTopic).
285→// ctx.api is the same Api object as bot.api, so we can pass a minimal shim.
286→function botFromCtx(ctx: Context): Bot {
287→  // createSessionTopic only uses bot.api.createForumTopic
288→  return { api: ctx.api } as unknown as Bot;
289→}
