291→// Skill command callback lookup map (short key → session + command)
292→interface SkillCallbackEntry {
293→  sessionId: string
294→  commandName: string
295→}
296→
297→const skillCallbackMap = new Map<string, SkillCallbackEntry>()
298→
299→export function buildSkillKeyboard(
300→  sessionId: string,
301→  commands: AgentCommand[],
302→): InlineKeyboard {
303→  const keyboard = new InlineKeyboard()
304→  const sorted = [...commands].sort((a, b) => a.name.localeCompare(b.name))
305→  for (let i = 0; i < sorted.length; i++) {
306→    const cmd = sorted[i]
307→    const key = nanoid(8)
308→    skillCallbackMap.set(key, { sessionId, commandName: cmd.name })
309→    keyboard.text(`/${cmd.name}`, `s:${key}`)
310→    if (i % 2 === 1 && i < sorted.length - 1) {
311→      keyboard.row()
312→    }
313→  }
314→  return keyboard
315→}
316→
317→export function clearSkillCallbacks(sessionId: string): void {
318→  for (const [key, entry] of skillCallbackMap) {
319→    if (entry.sessionId === sessionId) {
320→      skillCallbackMap.delete(key)
321→    }
322→  }
323→}
324→
325→export function setupSkillCallbacks(
326→  bot: Bot,
327→  core: OpenACPCore,
328→): void {
329→  bot.callbackQuery(/^s:/, async (ctx) => {
330→    try {
331→      await ctx.answerCallbackQuery()
332→    } catch { /* expired */ }
333→
334→    const key = ctx.callbackQuery.data.slice(2)
335→    const entry = skillCallbackMap.get(key)
336→    if (!entry) return
337→
338→    const session = core.sessionManager.getSession(entry.sessionId)
339→    if (!session || session.status !== 'active') return
340→
341→    await session.enqueuePrompt(`/${entry.commandName}`)
342→  })
343→}
