 44→  private bot!: Bot;
 45→  private telegramConfig: TelegramChannelConfig;
 46→  private sessionDrafts: Map<string, MessageDraft> = new Map();
 47→  private toolCallMessages: Map<
 48→    string,
 49→    Map<string, { msgId: number; name: string; kind?: string }>
 50→  > = new Map(); // sessionId → (toolCallId → state)
 51→  private permissionHandler!: PermissionHandler;
 52→  private assistantSession: Session | null = null;
 53→  private notificationTopicId!: number;
 54→  private assistantTopicId!: number;
 55→  private skillMessages: Map<string, number> = new Map(); // sessionId → pinned messageId
 56→
 57→  constructor(core: OpenACPCore, config: TelegramChannelConfig) {
 58→    super(core, config as never);
 59→    this.telegramConfig = config;
 60→  }
 61→
 62→  async start(): Promise<void> {
 63→    this.bot = new Bot(this.telegramConfig.botToken, { client: { fetch } });
 64→
 65→    // Global error handler — prevent unhandled errors from crashing the bot
 66→    this.bot.catch((err) => {
 67→      const rootCause = err.error instanceof Error ? err.error : err;
 68→      log.error({ err: rootCause }, "Telegram bot error");
 69→    });
 70→
 71→    // Ensure allowed_updates includes callback_query on every poll.
 72→    // bot.start() passes allowed_updates, but grammY only sends it on the first
 73→    // getUpdates call. Subsequent polls may omit the parameter, causing Telegram
 74→    // to fall back to its default (which excludes callback_query). This transformer
 75→    // guarantees callback_query is always requested.
 76→    this.bot.api.config.use((prev, method, payload, signal) => {
 77→      if (method === "getUpdates") {
 78→        const p = payload as never as Record<string, unknown>;
 79→        p.allowed_updates = (p.allowed_updates as string[] | undefined) ?? [
 80→          "message",
 81→          "callback_query",
 82→        ];
 83→      }
 84→      return prev(method, payload, signal);
 85→    });
 86→
 87→    // Register static commands for Telegram autocomplete (scoped to this chat)
 88→    await this.bot.api.setMyCommands(STATIC_COMMANDS, {
 89→      scope: { type: "chat", chat_id: this.telegramConfig.chatId },
 90→    });
 91→
 92→    // Middleware: only accept updates from configured chatId
 93→    this.bot.use((ctx, next) => {
 94→      const chatId = ctx.chat?.id ?? ctx.callbackQuery?.message?.chat?.id;
 95→      if (chatId !== this.telegramConfig.chatId) return;
 96→      return next();
 97→    });
 98→
 99→    // Ensure system topics exist
100→    const topics = await ensureTopics(
101→      this.bot,
102→      this.telegramConfig.chatId,
103→      this.telegramConfig,
104→      async (updates) => {
105→        // Save topic IDs to config
106→        await (this.core as OpenACPCore).configManager.save({
107→          channels: { telegram: updates },
108→        });
109→      },
110→    );
111→    this.notificationTopicId = topics.notificationTopicId;
112→    this.assistantTopicId = topics.assistantTopicId;
113→
114→    // Setup permission handler (instance only, callback registered later)
115→    this.permissionHandler = new PermissionHandler(
116→      this.bot,
117→      this.telegramConfig.chatId,
118→      (sessionId) =>
119→        (this.core as OpenACPCore).sessionManager.getSession(sessionId),
120→      (notification) => this.sendNotification(notification),
121→    );
122→
123→    // Callback registration order matters!
124→    // Specific regex handlers first, catch-all last.
125→    setupSkillCallbacks(this.bot, this.core as OpenACPCore);
126→    setupMenuCallbacks(
127→      this.bot,
128→      this.core as OpenACPCore,
129→      this.telegramConfig.chatId,
130→    );
131→    setupCommands(
132→      this.bot,
133→      this.core as OpenACPCore,
134→      this.telegramConfig.chatId,
135→    );
136→    this.permissionHandler.setupCallbackHandler();
137→
138→    // Setup message routing
139→    this.setupRoutes();
140→
141→    // Start bot polling
142→    this.bot.start({
143→      allowed_updates: ["message", "callback_query"],
144→      onStart: () =>
145→        log.info(
146→          { chatId: this.telegramConfig.chatId },
147→          "Telegram bot started",
148→        ),
149→    });
150→
151→    // Spawn assistant (after bot is started so it can send messages)
152→    try {
153→      this.assistantSession = await spawnAssistant(
154→        this.core as OpenACPCore,
155→        this,
156→        this.assistantTopicId,
157→      );
158→    } catch (err) {
159→      log.error({ err }, "Failed to spawn assistant");
160→    }
161→
162→    // Send welcome message with menu to assistant topic
163→    try {
164→      const config = (this.core as OpenACPCore).configManager.get();
165→      const agents = (
166→        this.core as OpenACPCore
167→      ).agentManager.getAvailableAgents();
168→      const agentList = agents
169→        .map(
170→          (a) =>
171→            `${escapeHtml(a.name)}${a.name === config.defaultAgent ? " (default)" : ""}`,
172→        )
173→        .join(", ");
174→      const workspace = escapeHtml(config.workspace.baseDir);
175→
176→      const welcomeText =
177→        `👋 <b>OpenACP Assistant</b> is online.\n\n` +
178→        `Available agents: ${agentList}\n` +
179→        `Workspace: <code>${workspace}</code>\n\n` +
180→        `<b>Select an action:</b>`;
181→
182→      await this.bot.api.sendMessage(this.telegramConfig.chatId, welcomeText, {
183→        message_thread_id: this.assistantTopicId,
184→        parse_mode: "HTML",
185→        reply_markup: buildMenuKeyboard(),
186→      });
187→    } catch (err) {
188→      log.warn({ err }, "Failed to send welcome message");
189→    }
190→  }
191→
192→  async stop(): Promise<void> {
193→    if (this.assistantSession) {
194→      await this.assistantSession.destroy();
195→    }
196→    await this.bot.stop();
197→    log.info("Telegram bot stopped");
198→  }
199→
200→  private setupRoutes(): void {
201→    this.bot.on("message:text", async (ctx) => {
202→      const threadId = ctx.message.message_thread_id;
203→
204→      // General topic or no thread → redirect to assistant
205→      if (!threadId) {
206→        const html = redirectToAssistant(
207→          this.telegramConfig.chatId,
208→          this.assistantTopicId,
209→        );
210→        await ctx.reply(html, { parse_mode: "HTML" });
211→        return;
212→      }
213→
214→      // Notification topic → ignore
215→      if (threadId === this.notificationTopicId) return;
216→
217→      // Assistant topic → send typing indicator and forward to assistant session
218→      if (threadId === this.assistantTopicId) {
219→        ctx.replyWithChatAction("typing").catch(() => {});
220→        handleAssistantMessage(this.assistantSession, ctx.message.text).catch(
221→          (err) => log.error({ err }, "Assistant error"),
222→        );
223→        return;
224→      }
225→
226→      // Session topic → send typing indicator and forward to core
227→      ctx.replyWithChatAction("typing").catch(() => {});
228→      (this.core as OpenACPCore)
229→        .handleMessage({
230→          channelId: "telegram",
231→          threadId: String(threadId),
232→          userId: String(ctx.from.id),
233→          text: ctx.message.text,
234→        })
235→        .catch((err) => log.error({ err }, "handleMessage error"));
236→    });
237→  }
238→
239→  // --- ChannelAdapter implementations ---
240→
241→  async sendMessage(
242→    sessionId: string,
243→    content: OutgoingMessage,
244→  ): Promise<void> {
245→    // log.debug({ sessionId, type: content.type }, "Sending message to Telegram");
246→    const session = (this.core as OpenACPCore).sessionManager.getSession(
247→      sessionId,
248→    );
249→    if (!session) return;
250→    const threadId = Number(session.threadId);
251→
252→    switch (content.type) {
253→      case "thought": {
254→        // Skip thought/thinking content — it's internal agent reasoning
255→        // Users don't need to see it
256→        break;
257→      }
258→
259→      case "text": {
260→        let draft = this.sessionDrafts.get(sessionId);
261→        if (!draft) {
262→          draft = new MessageDraft(
263→            this.bot,
264→            this.telegramConfig.chatId,
265→            threadId,
266→          );
267→          this.sessionDrafts.set(sessionId, draft);
268→        }
269→        draft.append(content.text);
270→        break;
271→      }
272→
273→      case "tool_call": {
274→        await this.finalizeDraft(sessionId);
275→        const meta = content.metadata as never as {
276→          id: string;
277→          name: string;
278→          kind?: string;
279→          status?: string;
280→          content?: unknown;
281→        };
282→        const msg = await this.bot.api.sendMessage(
283→          this.telegramConfig.chatId,
284→          formatToolCall(meta),
285→          {
286→            message_thread_id: threadId,
287→            parse_mode: "HTML",
288→            disable_notification: true,
289→          },
290→        );
291→        if (!this.toolCallMessages.has(sessionId)) {
292→          this.toolCallMessages.set(sessionId, new Map());
293→        }
294→        this.toolCallMessages.get(sessionId)!.set(meta.id, {
295→          msgId: msg.message_id,
296→          name: meta.name,
297→          kind: meta.kind,
298→        });
299→        break;
300→      }
301→
302→      case "tool_update": {
303→        const meta = content.metadata as never as {
304→          id: string;
305→          name: string;
306→          kind?: string;
307→          status: string;
308→          content?: unknown;
309→        };
310→        const toolState = this.toolCallMessages.get(sessionId)?.get(meta.id);
311→        if (toolState) {
312→          // Merge name/kind from original tool_call
313→          const merged = {
314→            ...meta,
315→            name: meta.name || toolState.name,
316→            kind: meta.kind || toolState.kind,
317→          };
318→          try {
319→            await this.bot.api.editMessageText(
320→              this.telegramConfig.chatId,
321→              toolState.msgId,
322→              formatToolUpdate(merged),
323→              { parse_mode: "HTML" },
324→            );
325→          } catch {
326→            /* edit failed */
327→          }
328→        }
329→        break;
330→      }
331→
332→      case "plan": {
333→        await this.finalizeDraft(sessionId);
334→        await this.bot.api.sendMessage(
335→          this.telegramConfig.chatId,
336→          formatPlan(
337→            content.metadata as never as {
338→              entries: Array<{ content: string; status: string }>;
339→            },
340→          ),
341→          {
342→            message_thread_id: threadId,
343→            parse_mode: "HTML",
344→            disable_notification: true,
345→          },
346→        );
347→        break;
348→      }
349→
350→      case "usage": {
351→        // Show usage stats
352→        await this.bot.api.sendMessage(
353→          this.telegramConfig.chatId,
354→          formatUsage(
355→            content.metadata as never as {
356→              tokensUsed?: number;
357→              contextSize?: number;
358→              cost?: { amount: number; currency: string };
359→            },
360→          ),
361→          {
362→            message_thread_id: threadId,
363→            parse_mode: "HTML",
364→            disable_notification: true,
365→          },
366→        );
367→        break;
368→      }
369→
370→      case "session_end": {
371→        await this.finalizeDraft(sessionId);
372→        this.sessionDrafts.delete(sessionId);
373→        this.toolCallMessages.delete(sessionId);
374→        await this.cleanupSkillCommands(sessionId);
375→        await this.bot.api.sendMessage(
376→          this.telegramConfig.chatId,
377→          `✅ <b>Done</b>`,
378→          {
379→            message_thread_id: threadId,
380→            parse_mode: "HTML",
381→            disable_notification: true,
382→          },
383→        );
384→        break;
385→      }
386→
387→      case "error": {
388→        await this.finalizeDraft(sessionId);
389→        await this.bot.api.sendMessage(
390→          this.telegramConfig.chatId,
391→          `❌ <b>Error:</b> ${escapeHtml(content.text)}`,
392→          {
393→            message_thread_id: threadId,
394→            parse_mode: "HTML",
395→            disable_notification: true,
396→          },
397→        );
398→        break;
399→      }
400→    }
401→  }
402→
403→  async sendPermissionRequest(
404→    sessionId: string,
405→    request: PermissionRequest,
406→  ): Promise<void> {
407→    log.info({ sessionId, requestId: request.id }, "Permission request sent");
408→    const session = (this.core as OpenACPCore).sessionManager.getSession(
409→      sessionId,
410→    );
411→    if (!session) return;
412→    await this.permissionHandler.sendPermissionRequest(session, request);
413→  }
414→
415→  async sendNotification(notification: NotificationMessage): Promise<void> {
416→    log.info(
417→      { sessionId: notification.sessionId, type: notification.type },
418→      "Notification sent",
419→    );
420→    if (!this.notificationTopicId) return;
421→    const emoji: Record<string, string> = {
422→      completed: "✅",
423→      error: "❌",
424→      permission: "🔐",
425→      input_required: "💬",
426→    };
427→    let text = `${emoji[notification.type] || "ℹ️"} <b>${escapeHtml(notification.sessionName || notification.sessionId)}</b>\n`;
428→    text += escapeHtml(notification.summary);
429→    if (notification.deepLink) {
430→      text += `\n\n<a href="${notification.deepLink}">→ Go to message</a>`;
431→    }
432→    await this.bot.api.sendMessage(this.telegramConfig.chatId, text, {
433→      message_thread_id: this.notificationTopicId,
434→      parse_mode: "HTML",
435→      disable_notification: false,
436→    });
437→  }
438→
439→  async createSessionThread(sessionId: string, name: string): Promise<string> {
440→    log.info({ sessionId, name }, "Session topic created");
441→    return String(
442→      await createSessionTopic(this.bot, this.telegramConfig.chatId, name),
443→    );
444→  }
445→
446→  async renameSessionThread(sessionId: string, newName: string): Promise<void> {
447→    const session = (this.core as OpenACPCore).sessionManager.getSession(
448→      sessionId,
449→    );
450→    if (!session) return;
451→    await renameSessionTopic(
452→      this.bot,
453→      this.telegramConfig.chatId,
454→      Number(session.threadId),
455→      newName,
456→    );
457→  }
458→
459→  async sendSkillCommands(
460→    sessionId: string,
461→    commands: AgentCommand[],
462→  ): Promise<void> {
463→    const session = (this.core as OpenACPCore).sessionManager.getSession(
464→      sessionId,
465→    );
466→    if (!session) return;
467→    const threadId = Number(session.threadId);
468→    if (!threadId) return;
469→
470→    // Empty commands → remove pinned message
471→    if (commands.length === 0) {
472→      await this.cleanupSkillCommands(sessionId);
473→      return;
474→    }
475→
476→    // Clear old callback entries before building new keyboard
477→    clearSkillCallbacks(sessionId);
478→
479→    const keyboard = buildSkillKeyboard(sessionId, commands);
480→    const text = "🛠 <b>Available commands:</b>";
481→    const existingMsgId = this.skillMessages.get(sessionId);
482→
483→    if (existingMsgId) {
484→      // Update existing pinned message
485→      try {
486→        await this.bot.api.editMessageText(
487→          this.telegramConfig.chatId,
488→          existingMsgId,
489→          text,
490→          { parse_mode: "HTML", reply_markup: keyboard },
491→        );
492→        return;
493→      } catch {
494→        // Message may have been deleted — fall through to create new
495→      }
496→    }
497→
498→    // Create and pin new message
499→    try {
500→      const msg = await this.bot.api.sendMessage(
501→        this.telegramConfig.chatId,
502→        text,
503→        {
504→          message_thread_id: threadId,
505→          parse_mode: "HTML",
506→          reply_markup: keyboard,
507→          disable_notification: true,
508→        },
509→      );
510→      this.skillMessages.set(sessionId, msg.message_id);
511→
512→      await this.bot.api.pinChatMessage(
513→        this.telegramConfig.chatId,
514→        msg.message_id,
515→        {
516→          disable_notification: true,
517→        },
518→      );
519→    } catch (err) {
520→      log.error({ err, sessionId }, "Failed to send skill commands");
521→    }
522→
523→    // Update Telegram autocomplete with skill commands
524→    await this.updateCommandAutocomplete(session.agentName, commands);
525→  }
526→
527→  async cleanupSkillCommands(sessionId: string): Promise<void> {
528→    const msgId = this.skillMessages.get(sessionId);
529→    if (!msgId) return;
530→
531→    try {
532→      await this.bot.api.editMessageText(
533→        this.telegramConfig.chatId,
534→        msgId,
535→        "🛠 <i>Session ended</i>",
536→        { parse_mode: "HTML" },
537→      );
538→      await this.bot.api.unpinChatMessage(this.telegramConfig.chatId, msgId);
539→    } catch {
540→      /* message may already be deleted */
541→    }
542→
543→    this.skillMessages.delete(sessionId);
544→    clearSkillCallbacks(sessionId);
545→  }
546→
547→  private async updateCommandAutocomplete(
548→    agentName: string,
549→    skillCommands: AgentCommand[],
550→  ): Promise<void> {
551→    // Telegram requires: 1-32 chars, lowercase a-z, 0-9, underscores only
552→    const prefix = `[${agentName}] `;
553→    const validSkills = skillCommands
554→      .map((c) => ({
555→        command: c.name
556→          .toLowerCase()
557→          .replace(/[^a-z0-9_]/g, "_")
558→          .slice(0, 32),
559→        description: (
560→          prefix + (c.description || c.name).replace(/\n/g, " ")
561→        ).slice(0, 256),
562→      }))
563→      .filter((c) => c.command.length > 0);
564→    const all = [...STATIC_COMMANDS, ...validSkills];
565→    try {
566→      await this.bot.api.setMyCommands(all, {
567→        scope: { type: "chat", chat_id: this.telegramConfig.chatId },
568→      });
569→      log.info(
570→        { count: all.length, skills: validSkills.length },
571→        "Updated command autocomplete",
572→      );
573→    } catch (err) {
574→      log.error(
575→        { err, commands: all },
576→        "Failed to update command autocomplete",
577→      );
578→    }
579→  }
580→
581→  private async finalizeDraft(sessionId: string): Promise<void> {
582→    const draft = this.sessionDrafts.get(sessionId);
583→    if (draft) {
584→      await draft.finalize();
585→      this.sessionDrafts.delete(sessionId);
586→    }
587→  }
588→}
589→

